JS_CODE = 'var Qs = [\n  "神経過敏に感じましたか？",\n  "絶望的だと感じましたか？",\n  "そわそわしたり、落ち着かない感じがしましたか？",\n  "気分が沈んだり、ふさぎ込んだりしましたか？",\n  "何をするのも骨折りだと感じましたか？",\n  "自分は価値のない人間だと感じましたか？",\n  "睡眠が十分に取れなかったと感じましたか？",\n  "疲れやすかったり、元気がなかったりしましたか？",\n  "物事に集中できなかったと感じましたか？",\n  "食欲がなかったり、食べ過ぎたりしましたか？"\n];\nvar OPTS = ["全くない（0）","少しだけ（1）","ときどき（2）","たいてい（3）","いつも（4）"];\n\nvar cur=0, total=0, scores=[];\n\nfunction startDiagnosis() { show(\'questions\'); renderQ(); }\n\nfunction show(name) {\n  document.querySelectorAll(\'.screen\').forEach(function(s){ s.classList.remove(\'active\'); });\n  document.getElementById(\'screen-\'+name).classList.add(\'active\');\n}\n\nfunction renderQ() {\n  var pct=Math.round((cur+1)/Qs.length*100);\n  document.getElementById(\'q-label\').textContent=\'質問 \'+(cur+1)+\' / \'+Qs.length;\n  document.getElementById(\'q-pct\').textContent=pct+\'%\';\n  document.getElementById(\'prog\').style.width=pct+\'%\';\n  document.getElementById(\'q-text\').textContent=Qs[cur];\n  var c=document.getElementById(\'opts\'); c.innerHTML=\'\';\n  OPTS.forEach(function(opt,i){\n    var b=document.createElement(\'button\');\n    b.className=\'option-btn\'; b.textContent=opt;\n    b.onclick=function(){ pick(i); };\n    c.appendChild(b);\n  });\n}\n\nfunction pick(score) {\n  scores.push(score);\n  total+=score;\n  document.querySelectorAll(\'.option-btn\').forEach(function(b,j){ b.classList.toggle(\'selected\',j===score); });\n  setTimeout(function(){\n    cur++;\n    if(cur<Qs.length){ renderQ(); } else { show(\'loading\'); setTimeout(showResults,1600); }\n  },300);\n}\n\nvar levels = [\n  { max:9,  emoji:\'😊\', text:\'低ストレス\', color:\'#0d9488\', desc:\'現在のストレス状態は良好です。日々の生活リズムを維持して、予防的なセルフケアを続けましょう。\', care:[\'定期的な運動（週3回以上）\',\'十分な睡眠（7〜8時間）\',\'趣味の時間を確保する\',\'人との交流を大切にする\'] },\n  { max:14, emoji:\'😐\', text:\'中程度のストレス\', color:\'#f59e0b\', desc:\'多少のストレスを感じている状態です。放置すると蓄積しやすいため、早めにケアすることが大切です。\', care:[\'深呼吸・瞑想（1日10分）\',\'ストレスの原因を書き出す\',\'信頼できる人に話を聞いてもらう\',\'デジタルデトックスを試みる\'] },\n  { max:19, emoji:\'😟\', text:\'高ストレス\', color:\'#f97316\', desc:\'かなりのストレスを感じている状態です。心身への影響が出やすくなっています。積極的なケアが必要です。\', care:[\'専門家（カウンセラー）への相談を検討\',\'業務・タスクの見直し\',\'医療機関での相談（心療内科）\',\'週1回は完全オフの日を作る\'] },\n  { max:40, emoji:\'😰\', text:\'要注意ストレス\', color:\'#dc2626\', desc:\'深刻なストレス状態の可能性があります。放置は危険です。早めに専門家への相談を強くおすすめします。\', care:[\'すぐに専門家に相談する\',\'一人で抱え込まない\',\'緊急の場合は相談窓口へ（よりそいホットライン: 0120-279-338）\',\'まず休むことを最優先に\'] }\n];\n\nfunction showResults() {\n  var pct = Math.round(total/40*100);\n  var level = levels[0];\n  for(var i=0;i<levels.length;i++){\n    if(total<=levels[i].max){ level=levels[i]; break; }\n  }\n\n  document.getElementById(\'res-emoji\').textContent=level.emoji;\n  document.getElementById(\'res-level-text\').textContent=level.text;\n  document.getElementById(\'res-level-text\').style.color=level.color;\n  document.getElementById(\'res-score-text\').textContent=\'スコア: \'+total+\'/40点 (\'+pct+\'%)\';\n  document.getElementById(\'res-meter\').style.width=pct+\'%\';\n  document.getElementById(\'res-meter\').style.background=level.color;\n  document.getElementById(\'res-desc\').textContent=level.desc;\n\n  var careEl=document.getElementById(\'res-care\');\n  careEl.innerHTML=\'\';\n  level.care.forEach(function(c){ var li=document.createElement(\'li\'); li.textContent=\'• \'+c; careEl.appendChild(li); });\n\n  var affArea=document.getElementById(\'aff-area\');\n  if(total>=15) {\n    affArea.innerHTML=\'<div class="bg-teal-50 border border-teal-200 rounded-xl p-4 mb-2"><div class="font-bold text-teal-800 mb-1">オンラインカウンセリングを試してみる</div><p class="text-xs text-gray-600 mb-3">自宅にいながらスマホで相談できる。初回カウンセリング無料のサービスも。</p><a href="https://px.a8.net/svt/ejp?a8mat=4B3WJ8+5DK6Y2+5ULO+5YZ75" rel="nofollow" target="_blank" rel="noopener sponsored" class="block text-center bg-teal-600 text-white font-bold py-3 rounded-lg text-sm hover:bg-teal-700 transition">無料で相談する →</a></div>\';\n  } else {\n    affArea.innerHTML=\'<div class="bg-teal-50 border border-teal-200 rounded-xl p-4 mb-2"><div class="font-bold text-teal-800 mb-1">マインドフルネス・瞑想アプリで予防を</div><p class="text-xs text-gray-600 mb-3">毎日10分の瞑想でストレス耐性を高める。予防ケアで良好な状態を維持。</p><a href="https://px.a8.net/svt/ejp?a8mat=4B3WJ8+9PJRFU+4ABU+6G4HD" rel="nofol'
